const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

app.get('/images/:tag', async (req, res) => {
  const{ tag } = req.query;
  if (!tag) {
    return res.status(400).json({ error: 'Tag parameter is required' });
  }

  try {
    const imageUrl = await axios.get(`https://pornpics.com/tags/${tag}`);
    // In a real scenario, parse actual HTML content or serve direct image paths
    res.json({
      url: imageUrl,
      path: `/images${tag}`
    });
  } catch (err) {
    res.status(500).json({ error: 'Failed to load image', imageUrl: err.message });
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

